#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        int breakfast, lunch, dinner, calories_burned;
        scanf("%d %d %d %d", &breakfast, &lunch, &dinner, &calories_burned);
        int total_calories = breakfast + lunch + dinner;
        int net_calorie_intake = total_calories - calories_burned;
        printf("Total Calories Consumed: %d\n", total_calories);
        printf("Calories Burned: %d\n", calories_burned);
        printf("Net Calorie Intake: %d\n", net_calorie_intake);
        if (tc != T-1) printf("\n");
    }
    return 0;
}

