code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int breakfast = Integer.parseInt(st.nextToken());
            int lunch = Integer.parseInt(st.nextToken());
            int dinner = Integer.parseInt(st.nextToken());
            int caloriesBurned = Integer.parseInt(st.nextToken());
            int total = breakfast + lunch + dinner;
            int net = total - caloriesBurned;
            sb.append("Total Calories Consumed: ").append(total).append('\n');
            sb.append("Calories Burned: ").append(caloriesBurned).append('\n');
            sb.append("Net Calorie Intake: ").append(net).append('\n');
            if (tc != T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

